sql:
SELECT model_name, framework
FROM models
WHERE training_time >= 5;

external_knowledge:
- 'evaluation metrics' refers to pose, background, pattern, and color; 
- 'top-performing models' means the models with the highest evaluation metrics in each dataset; 
- 'average performance of all models' is the average of pose, background, pattern, and color evaluation metrics for all models in a dataset.

; Best-performing model refers to the model with the highest average evaluation metric across all models; 
; The evaluation metric ID for 'average' is assumed to be a unique identifier for the 'average' metric in the evaluation_metrics table; 
; The confidence threshold used for evaluation is assumed to be a measure of the reliability of the evaluation results.

sql:
SELECT COUNT(DISTINCT model_id) AS num_results
FROM evaluation_results
WHERE average > 0.7;
